// Entry Validation Node - Validates and sanitizes form data
const body = $input.first().json.body;
const result = { valid: true, errors: [], warnings: [], normalized: {}, original: body, _meta: { receivedAt: new Date().toISOString() } };

const validateEmail = (email) => {
  if (!email || typeof email !== 'string') return { valid: false, reason: 'Email is required' };
  const trimmed = email.trim().toLowerCase();
  if (trimmed.length === 0) return { valid: false, reason: 'Email is empty' };
  if (trimmed.length > 254) return { valid: false, reason: 'Email too long' };
  if (!trimmed.includes('@')) return { valid: false, reason: 'Missing @ symbol' };
  const [local, domain] = trimmed.split('@');
  if (!local || local.length === 0) return { valid: false, reason: 'Local part empty' };
  if (local.length > 64) return { valid: false, reason: 'Local part too long' };
  if (local.startsWith('.') || local.endsWith('.')) return { valid: false, reason: 'Local part cannot start/end with dot' };
  if (local.includes('..')) return { valid: false, reason: 'Consecutive dots in local part' };
  if (!domain || domain.length === 0) return { valid: false, reason: 'Domain empty' };
  if (!domain.includes('.')) return { valid: false, reason: 'Missing TLD' };
  const tld = domain.substring(domain.lastIndexOf('.') + 1);
  if (tld.length < 2) return { valid: false, reason: 'TLD too short' };
  const emailRegex = /^[a-z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-z0-9](?:[a-z0-9-]{0,61}[a-z0-9])?(?:\.[a-z0-9](?:[a-z0-9-]{0,61}[a-z0-9])?)*$/;
  if (!emailRegex.test(trimmed)) return { valid: false, reason: 'Invalid email format' };
  return { valid: true, normalized: trimmed };
};

const parseFullName = (fullName) => {
  if (!fullName || typeof fullName !== 'string') return { firstName: 'Unknown', lastName: '' };
  const clean = fullName.trim().replace(/\s+/g, ' ');
  if (clean.length === 0) return { firstName: 'Unknown', lastName: '' };
  const parts = clean.split(' ');
  return {
    firstName: parts[0],
    lastName: parts.slice(1).join(' ')
  };
};

// Email validation
const emailValidation = validateEmail(body.data?.email);
if (!emailValidation.valid) {
  result.valid = false;
  result.errors.push(`Email: ${emailValidation.reason}`);
} else {
  result.normalized.email = emailValidation.normalized;
}

// Name parsing
const nameParts = parseFullName(body.data?.name);
result.normalized.firstName = nameParts.firstName;
result.normalized.lastName = nameParts.lastName;

// Company validation
const company = body.data?.company?.trim();
if (!company) {
  result.warnings.push('Company name not provided');
  result.normalized.company = 'Unknown Company';
} else {
  result.normalized.company = company;
}

// Other fields
result.normalized.jobTitle = body.data?.role || body.data?.jobTitle;
result.normalized.message = body.data?.message;
result.normalized.phone = body.data?.phone;
result.normalized.teamSize = body.data?.teamSize;
result.normalized.securityLevel = body.data?.securityLevel;
result.normalized.techStack = Array.isArray(body.data?.techStack) ? body.data.techStack.join(', ') : body.data?.techStack || '';
result.normalized.compliance = Array.isArray(body.data?.compliance) ? body.data.compliance.join(', ') : body.data?.compliance || '';

// Track validation time
result._meta.validatedAt = new Date().toISOString();

return [{ json: result }];

// Prepare data for parallel branches with error tracking
const input = $input.first().json;
const data = input.normalized;

// Calculate domain for company
const domain = data.email?.split('@')[1] || '';

// Shared note data
const noteData = {
  message: data.message || '',
  techStack: data.techStack || '',
  compliance: data.compliance || '',
  teamSize: data.teamSize || '',
  securityLevel: data.securityLevel || '',
  submittedAt: input._meta?.receivedAt || new Date().toISOString()
};

// Return two outputs for parallel branches
return [
  {
    json: {
      branch: 'person',
      personData: {
        name: { firstName: data.firstName, lastName: data.lastName },
        emails: [{ email: data.email, isPrimary: true }],
        jobTitle: data.jobTitle || undefined,
        phones: data.phone ? [{ number: data.phone, isPrimary: true }] : undefined
      },
      companyName: data.company,
      noteData: noteData,
      _meta: {
        branchStartTime: Date.now()
      }
    }
  },
  {
    json: {
      branch: 'company',
      companyData: {
        name: data.company,
        domainName: domain || undefined
      },
      personEmail: data.email,
      noteData: noteData,
      _meta: {
        branchStartTime: Date.now()
      }
    }
  }
];

// Extract Person ID with error handling
const response = $input.first().json;
const startTime = $input.first().json._meta?.branchStartTime || Date.now();
const duration = Date.now() - startTime;

// Check for HTTP errors
const hasError = response.error !== undefined || (response.statusCode && response.statusCode >= 400);
const personId = !hasError ? (response.data?.id || response.id) : null;

const result = {
  personId: personId,
  personSuccess: !!personId && !hasError,
  personError: hasError ? (response.error?.message || response.message || 'Unknown error') : null,
  personStatusCode: response.statusCode || 200,
  personDuration: duration,
  noteData: $input.first().json.noteData,
  companyName: $input.first().json.companyName,
  _meta: {
    extractedAt: Date.now()
  }
};

// Log error if present
if (hasError) {
  console.error(`[PARALLEL] Person creation failed: ${result.personError}`);
}

return [{ json: result }];

// Extract Company ID with error handling
const response = $input.first().json;
const startTime = $input.first().json._meta?.branchStartTime || Date.now();
const duration = Date.now() - startTime;

// Check for HTTP errors
const hasError = response.error !== undefined || (response.statusCode && response.statusCode >= 400);
const companyId = !hasError ? (response.data?.id || response.id) : null;

const result = {
  companyId: companyId,
  companySuccess: !!companyId && !hasError,
  companyError: hasError ? (response.error?.message || response.message || 'Unknown error') : null,
  companyStatusCode: response.statusCode || 200,
  companyDuration: duration,
  noteData: $input.first().json.noteData,
  _meta: {
    extractedAt: Date.now()
  }
};

// Log error if present
if (hasError) {
  console.error(`[PARALLEL] Company creation failed: ${result.companyError}`);
}

return [{ json: result }];

// Combine Person and Company results with comprehensive error handling
const inputs = $input.all();
const personInput = inputs[0].json;
const companyInput = inputs[1].json;

// Determine overall success
const personSuccess = personInput.personSuccess;
const companySuccess = companyInput.companySuccess;
const totalFailures = (personSuccess ? 0 : 1) + (companySuccess ? 0 : 1);

// Handle complete failure
if (totalFailures === 2) {
  throw new Error(`PARALLEL_FAILURE: Both Person and Company creation failed. Person: ${personInput.personError}, Company: ${companyInput.companyError}`);
}

// Log partial failure
if (totalFailures === 1) {
  console.warn(`[PARALLEL] Partial failure detected. Person success: ${personSuccess}, Company success: ${companySuccess}`);
}

const result = {
  personId: personInput.personId,
  companyId: companyInput.companyId,
  personSuccess: personSuccess,
  companySuccess: companySuccess,
  personError: personInput.personError,
  companyError: companyInput.companyError,
  personDuration: personInput.personDuration,
  companyDuration: companyInput.companyDuration,
  partialFailure: totalFailures === 1,
  noteData: personInput.noteData || companyInput.noteData,
  _meta: {
    mergedAt: Date.now(),
    parallelDuration: Math.max(personInput.personDuration || 0, companyInput.companyDuration || 0)
  }
};

return [{ json: result }];

